// input: $json.product (user search string)

const original = ($json.product || '').trim();
if (!original) {
  return [{ json: { error: 'empty search' } }];
}

// sanitize
const cleaned = original.replace(/[\"']/g, '').replace(/[^\w\s-]/g, ' ').replace(/\s+/g, ' ').trim();
const tokens = cleaned.split(/\s+/).filter(Boolean);

// build titleQuery requiring each token in title
const titleQuery = tokens.map(t => `title:${t}`).join(' ');

// exact phrase
const phraseQuery = `\"${cleaned}\"`;

// generate candidate vendor n-grams (longest-first)
const vendorCandidates = [];
for (let len = tokens.length; len >= 1; len--) {
  for (let i = 0; i + len <= tokens.length; i++) {
    vendorCandidates.push(tokens.slice(i, i + len).join(' '));
  }
}

return [{ json: { original, cleaned, tokens, titleQuery, phraseQuery, vendorCandidates } }];

parameters.query:
query ProductsByTitle($query: String!) {
  products(first: 10, query: $query) {
    edges {
      node {
        id
        title
        handle
        vendor
        variantsCount { count }
        options(first: 20) { name values }
        onlineStoreUrl
        featuredImage { url altText width height }
        variants(first: 20) {
          edges {
            node {
              id
              title
              availableForSale
              price { amount currencyCode }
              compareAtPrice { amount currencyCode }
            }
          }
        }
      }
    }
  }
}

